var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"찾았다, 쥐새끼들.","JPN":"見つけた、ネズミども。","ENG":"I found you. You little rats.","TWN":"哟，老鼠們。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?!","JPN":"な、なに！？","ENG":"W-what?","TWN":"什、什麼！？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......홀로그램 통신장치로군.","JPN":"……ホログラムの通信装置だな。","ENG":"...It's a hologram communication device.","TWN":"……是全息影像通信裝置吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 방 안에 설치되어 있었나 본데?","JPN":"この部屋の中に取り付けられているようだ。","ENG":"I guess there was one installed in this room.","TWN":"看來這個房間裡設置了這種東西。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"다들 쥐새끼답게 옹기종기 잘들 모여 있군.","JPN":"さすがはネズミども。仲良く1カ所に群がってるな。","ENG":"You're all gathered together like little rats.","TWN":"大家都像老鼠一樣擠在一起呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"마지막 수다는 다 떨었나?","JPN":"最後のおしゃべりは楽しめたか？","ENG":"Are you done with the last chat of your petty little lives?","TWN":"是因為這是最後一次聊天，所以在瑟瑟發抖了嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"괜찮으면 슬슬 쥐약을 살포하려고 하는데 말이지.","JPN":"よければ、そろそろネズミ駆除剤を散布しようと思うのだが。","ENG":"We're about to spray the rat poison if you're ready.","TWN":"你們想要的話，要不要我撒點老鼠藥啊。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......누구야, 저 노출광은?","JPN":"……誰、あの露出魔は？","ENG":"Who's the stripper?","TWN":"……誰啊！這個暴露狂！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"나도 직접 보는 건 처음이지만...... 사진으로 본 기억이 있군.","JPN":"俺もリアルで見るのは初めてだが……写真で見た覚えがあるな。","ENG":"It's my first time seeing her in person... But I've seen her picture before.","TWN":"雖然我是第一次親眼看到……但我記得我在照片上看過妳！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......코드명 리플레이서 나이트.","JPN":"……コード名、リプレイサー・ナイト。","ENG":"Code Name: Replacer Knight.","TWN":"代碼名：克隆·騎士。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"현재 37개국에서 지명 수배된 1급 테러리스트다.","JPN":"現在、37カ国から指名手配を受けている第1級テロリストだ。","ENG":"She's a Class 1 terrorist on the wanted list in 37 countries.","TWN":"現在是37個國家通緝的一級恐怖份子。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하! 나도 꽤나 유명인사가 된 모양이네.","JPN":"ハハハ！　アタシもすっかり有名人だね。","ENG":"Haha! I guess I've gotten pretty famous!","TWN":"哈哈！那我也算是個名人了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......뻔뻔스럽군.","JPN":"……厚かましい奴め。","ENG":"More like infamous...","TWN":"……真不要臉。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이런 곳에서 얼굴을 드러낸 걸 보니, 아마 네놈이 이번 사건의 주동자인가 보지?","JPN":"ここで姿を表したということは、お前が今回の事件を主導した張本人なんだな？","ENG":"If you're talking to us, you must be the mastermind behind all of this?","TWN":"會在這裡露臉，看來妳這傢伙就是這次事件的主謀囉？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"넌 선을 넘어도 한참 넘었어.","JPN":"お前は、とっくのとうに一線を越えちまったんだ。","ENG":"You've gone too far this time.","TWN":"妳已經超過我很多的底線了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"감히 합중국의 요원을 살해하고 민간인을 공격하다니.......","JPN":"合衆国の要人を殺害しただけでなく、民間人まで攻撃するなんて……","ENG":"How dare you murder federal agents and attack innocent civilians...","TWN":"竟敢殺害合眾國的要員、還攻擊平民……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......대가를 치르게 될 거다.","JPN":"……代償を払ってもらうぞ。","ENG":"You'll pay dearly for this...","TWN":"……妳會付出代價的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};